Vtiger_Detail_Js("Project_Detail_Js",{},{detailViewRecentTicketsTabLabel:"Trouble Tickets",detailViewRecentTasksTabLabel:"Project Tasks",detailViewRecentMileStonesLabel:"Project Milestones",registerSummaryViewContainerEvents:function(e){this._super(e)},loadModuleSummary:function(){var e={};e.module=app.getModuleName(),e.view="Detail",e.mode="showModuleSummaryView",e.record=jQuery("#recordId").val(),AppConnector.request(e).then(function(e){jQuery(".summaryView").html(e)})},registerEvents:function(){var e=this.getContentHolder(),t=this;this._super(),e.on("click",".moreRecentMilestones",function(){t.getTabByLabel(t.detailViewRecentMileStonesLabel).trigger("click")}),e.on("click",".moreRecentTickets",function(){t.getTabByLabel(t.detailViewRecentTicketsTabLabel).trigger("click")}),e.on("click",".moreRecentTasks",function(){t.getTabByLabel(t.detailViewRecentTasksTabLabel).trigger("click")})}});